#!/usr/bin/env bash
# slo-error-budget-sop-pick-sli-se.sh — SLO 定义 + error budget SOP（pick SLI → set SLO → error budget policy → burn-rate alerting） SOP walkthrough for DevOps 与 SRE.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="DevOps 与 SRE"
WORKFLOW="SLO 定义 + error budget SOP（pick SLI → set SLO → error budget policy → burn-rate alerting）"

usage() {
  cat <<EOF
slo-error-budget-sop-pick-sli-se.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./slo-error-budget-sop-pick-sli-se.sh             # interactive
  ./slo-error-budget-sop-pick-sli-se.sh --dry-run
  ./slo-error-budget-sop-pick-sli-se.sh --json
  ./slo-error-budget-sop-pick-sli-se.sh --explain
  ./slo-error-budget-sop-pick-sli-se.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "SLO 定义 + error budget SOP（pick SLI → set SLO → error budget policy → burn-rate alerting）" 工作流。

入门 SOP 共 5 步, 失败模式自检 0 项。

相关心智模型:
  • 错误预算思维 — 可靠性是产品决策, 不是技术债; 100% 是错误的目标: 可靠性不是越高越好 — `error budget = 1 - SLO` 是一笔可花的预算, 它把"该发功能还是修可靠性"从情绪/道德争论变成 dev/SRE/产品三方共享的数字决策; 盲目追 100
  • 小批量高频部署 > 少发布 (反直觉) — 速度与稳定不是 trade-off: 直觉是"少发布就少出事", 但 DORA 用 23,000+ 受访者的统计学证明这是错的 — 低部署频率 = 大批量变更 = 更高 change failure rate + 更难定位; elite 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "选 SLI（按用户体验）：测真正影响用户的指标——可用性（成功请求比）、延迟（p99）、正确性"
  "定 SLO 目标（基于历史 + 现实）：如 99.9% 成功率/30 天。不是越高越好"
  "算 error budget = 1 − SLO：99.9% → 每 30 天约 43 分钟不可用预算"
  "写 error budget policy：预算烧光时的明文动作（如冻结发布、全员转修可靠性）"
  "配 burn-rate 告警：基于\"预算消耗速度\"而非瞬时错误率告警"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "slo-error-budget-sop-pick-sli-se-walkthrough"
fi
